export function nextGeneration(cells: [number, number][]): [number, number][] {
  const survivors = cells.filter(cell => {
    const neighborCount = countNeighbors(cell, cells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const deadCandidates: [number, number][] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const isLive = cells.some(([cx, cy]) => cx === nx && cy === ny);
        const alreadyAdded = deadCandidates.some(([cx, cy]) => cx === nx && cy === ny);
        if (!isLive && !alreadyAdded) {
          deadCandidates.push([nx, ny]);
        }
      }
    }
  }

  const born = deadCandidates.filter(cell => countNeighbors(cell, cells) === 3);

  return [...survivors, ...born];
}

